def min_parallel_time(tasks, c):
    n = len(tasks)
    if n == 0:
        return 0
    if n == 1:
        return tasks[0]

    prefix = [0] * (n + 1)
    for i in range(n):
        prefix[i + 1] = prefix[i] + tasks[i]

    dp = [[0] * n for _ in range(n)]

    for i in range(n):
        dp[i][i] = tasks[i]

    for length in range(2, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1
            # Option 1: sequential
            dp[i][j] = prefix[j + 1] - prefix[i]
            # Option 2: split at some point k
            for k in range(i, j):
                val = max(dp[i][k], dp[k + 1][j]) + c
                if val < dp[i][j]:
                    dp[i][j] = val

    return dp[0][n - 1]

