import unittest

class TestSolution(unittest.TestCase):
    # Visible tests
    def test_basic(self):
        self.assertEqual(min_parallel_time([4, 2, 3], 1), 5)

    def test_balanced_split(self):
        self.assertEqual(min_parallel_time([5, 5, 5, 5], 2), 12)

    def test_recursive_split(self):
        self.assertEqual(min_parallel_time([1, 1, 1, 1, 1, 1, 1, 1], 1), 4)

    # Hidden tests
    def test_hidden_empty(self):
        self.assertEqual(min_parallel_time([], 5), 0)

    def test_hidden_single(self):
        self.assertEqual(min_parallel_time([10], 5), 10)

    def test_hidden_zero_overhead(self):
        # c=0 means unlimited free parallelism; answer = max element
        self.assertEqual(min_parallel_time([5, 5, 5, 5], 0), 5)

    def test_hidden_large_overhead(self):
        # c so large that sequential is always best
        self.assertEqual(min_parallel_time([3, 1, 4, 1, 5], 100), 14)

    def test_hidden_two_equal(self):
        self.assertEqual(min_parallel_time([10, 10], 1), 11)

    def test_hidden_dominant_task(self):
        # One huge task dominates; splitting never helps
        self.assertEqual(min_parallel_time([1, 100, 1], 1), 102)

    def test_hidden_mixed(self):
        self.assertEqual(min_parallel_time([2, 8, 4, 6], 2), 12)

    def test_hidden_increasing(self):
        self.assertEqual(min_parallel_time([1, 2, 3, 4], 1), 5)

    def test_hidden_power_of_two(self):
        # 16 ones with c=1: balanced binary tree depth 4 → 1+4=5
        self.assertEqual(min_parallel_time([1]*16, 1), 5)

if __name__ == '__main__':
    unittest.main()
